impl Solution { pub fn find_redundant_connection(black_edges: Vec<Vec<i32>>) -> Vec<i32> { let mut black_p: Vec<usize> = (0..=black_edges.len()).collect(); fn find(i: usize, p: &mut Vec<usize>) -> usize { if p[i] == i { i } else { p[i] = find(p[i], p); p[i] } } for e in black_edges { let (u, v) = (find(e[0] as usize, &mut black_p), find(e[1] as usize, &mut black_p)); if u == v { return e; } black_p[u] = v; } vec![] } }